class Structure:
 def __init__(self):
 self.member_name = None

structure = Structure()
structure.member_name = 'value'
print(structure.member_name)

#include <stdio.h>

struct Structure {
 char member_name[20];
};

int main() {
 struct Structure structure;
 strcpy(structure.member_name, "value");
 printf("%s\n", structure.member_name);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Structure {
 char member_name[20];
};

int main() {
 struct Structure* structure = malloc(sizeof(struct Structure));
 strcpy(structure->member_name, "value");
 printf("%s\n", structure->member_name);
 free(structure);
 return 0;
}
